        }
        return Ok(result);
    }

    [HttpPost("document")]
    [RequestSizeLimit(25 * 1024 * 1024)]
    public async Task<IActionResult> UploadDocument(IFormFile file)
    {
        var result = await ProcessUpload(file, UploadType.Document);
        if (!result.Success)
        {
            return BadRequest(new { error = result.ErrorMessage });
        }
        return Ok(result);
    }

    [HttpPost("documents")]
    [RequestSizeLimit(100 * 1024 * 1024)]
    public async Task<IActionResult> UploadDocuments(List<IFormFile> files)
    {
        if (files == null || files.Count == 0)
        {
            return BadRequest(new { error = "No files provided." });
        }

        if (files.Count > 10)
        {
            return BadRequest(new { error = "Maximum 10 files allowed per upload." });
        }

        var results = new List<FileUploadResult>();
        foreach (var file in files)
        {
            var result = await ProcessUpload(file, UploadType.Document);
            results.Add(result);
        }

        var allSuccessful = results.All(r => r.Success);
        if (allSuccessful)
        {
            return Ok(new { results });
        }

        return BadRequest(new { results });
    }

    private async Task<FileUploadResult> ProcessUpload(IFormFile file, UploadType uploadType)
