            return result;
        }

        // Get and sanitize the file extension
        var originalFileName = file.FileName;
        var extension = Path.GetExtension(originalFileName)?.ToLowerInvariant();

        if (string.IsNullOrEmpty(extension))
        {
            result.ErrorMessage = "File must have an extension.";
            return result;
        }

        // Check for dangerous extensions
        if (FileUploadSettings.DangerousExtensions.Contains(extension))
        {
            result.ErrorMessage = "This file type is not allowed for security reasons.";
            return result;
        }

        // Check for double extensions (e.g., file.php.jpg trick - validate all parts)
        var fileNameWithoutExtension = Path.GetFileNameWithoutExtension(originalFileName);
        if (fileNameWithoutExtension.Contains('.'))
        {
            var parts = originalFileName.Split('.');
            foreach (var part in parts.Skip(1).Take(parts.Length - 2))
            {
                var intermediateExt = "." + part.ToLowerInvariant();
                if (FileUploadSettings.DangerousExtensions.Contains(intermediateExt))
                {
