    private static async Task<bool> IsFileSignatureValid(IFormFile file, string extension)
    {
        if (!FileUploadSettings.FileSignatures.TryGetValue(extension, out var signatures))
        {
            // For file types without defined signatures (e.g., .txt, .csv), skip signature check
